  const words = normalized.split(/\s+/).filter(w => w.length > 3).slice(0, 6).map(w => w.replace(/'/g, ''));
  if (words.length === 0) {
    return "SELECT titulo, categoria, NULL::text as conteudo FROM dashboard_pops WHERE ativo = true ORDER BY categoria, titulo";
  }
  const conditions = words.map(w => `(titulo ILIKE '%${w}%' OR LEFT(conteudo, 500) ILIKE '%${w}%')`).join(' OR ');
  return `SELECT titulo, categoria, CASE WHEN (${conditions}) THEN conteudo ELSE NULL END as conteudo FROM dashboard_pops WHERE ativo = true ORDER BY categoria, titulo`;
})() }}

