// ============================================================
// MONTA PROMPT - COM DEDUPLICAÇÃO E TRAVA DE EXECUÇÃO
// ============================================================

// 1. REGRAS (Deduplicar)
let rules = '';
try {
  const rulesData = $('Busca Regras').all().map(r => r.json.regra).filter(Boolean);
  const uniqueRules = [...new Set(rulesData)];
  rules = uniqueRules.slice(0, 30).join('\n- ');
} catch(e) {}
const rulesPrompt = rules ? '\n\n⚠️ REGRAS ADICIONAIS DE TREINAMENTO (Siga Rigorosamente):\n- ' + rules : '';

// 2. SYSTEM PROMPT (Primeiro disponível)
let systemPromptTemplate = null;
try {
  const spData = $('Busca System Prompt').all().map(d => d.json?.valor).filter(Boolean);
  systemPromptTemplate = spData[0] || null;
  if (systemPromptTemplate && systemPromptTemplate.length > 40000) {
    systemPromptTemplate = systemPromptTemplate.substring(0, 40000) + '\n[...truncado...]';
  }
} catch(e) {}

// 3. HISTÓRICO (Deduplicar por ID)
let historicoSection = '';
try {
  const histRows = $('Busca Histórico 10').all().map(e => e.json);
  const histMap = new Map();
  for (const h of histRows) {
    if (h.id) histMap.set(h.id, h);
  }
  const uniqueHist = Array.from(histMap.values()).sort((a,b) => a.id - b.id).slice(-10);
  let historico = '';
  for (const msg of uniqueHist) {
    let hora = '??:??';
    try {
      const d = new Date(new Date(msg.data_hora).getTime() - 3 * 60 * 60 * 1000);
      hora = d.toISOString().substring(11, 16);
    } catch(e) {}
    historico += `[${hora}] ${msg.remetente}: ${(msg.mensagem || '').substring(0, 300)}\n`;
  }
  if (historico) historicoSection = `\n\nÚLTIMAS MENSAGENS DO GRUPO:\n${historico}`;
} catch(e) {}

// 4. POPs (Deduplicar por Título e Filtrar por Categoria)
const allPopsInputs = $input.all().map(i => i.json).filter(p => p.titulo);
const popMap = new Map();
for (const p of allPopsInputs) {
  if (p.conteudo || !popMap.has(p.titulo)) {
    popMap.set(p.titulo, p);
  }
}
const uniquePops = Array.from(popMap.values());

let clientesContent = '';
const allNonClientTitles = [];
const relevantNonClientPops = [];

for (const pop of uniquePops) {
  const cat = (pop.categoria || '').toLowerCase();
  const isClientDB = cat.includes('cliente') || cat.includes('banco') || cat.includes('base') || cat.includes('crm');
  if (isClientDB) {
    if (pop.conteudo) clientesContent += pop.conteudo + '\n';
  } else {
    allNonClientTitles.push(pop);
    if (pop.conteudo) relevantNonClientPops.push(pop);
  }
}

// 5. COLABORADORES (Deduplicar por Nome)
let colaboradoresArray = [];
try {
  const colabRows = $('Busca Colaboradores').all().map(i => i.json).filter(c => c.nome);
  const colabMap = new Map();
  for (const c of colabRows) {
    colabMap.set(c.nome, c);
  }
  colaboradoresArray = Array.from(colabMap.values());
} catch(e) {}

// 6. DADOS DA MENSAGEM ATUAL
let _vM; 
try { _vM = $('Verifica Menção').first().json; if (!_vM.chatId) _vM = null; } catch(e) {}
if (!_vM) try { _vM = $('Formata Transcrição').first().json; } catch(e) { _vM = {}; }
const chatId = _vM.chatId || '';
const textMessage = _vM.textMessage || '';

const now = new Date();
const brt = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const dia = brt.getDate().toString().padStart(2,'0');
const mes = (brt.getMonth()+1).toString().padStart(2,'0');
const ano = brt.getFullYear();
const today = `${ano}-${mes}-${dia}`;

const msgLower = textMessage.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// 7. SELEÇÃO DE POPS NO PROMPT
const isListingPops = msgLower.includes('pop') || msgLower.includes('procedimento') || msgLower.includes('quais') || msgLower.includes('lista');
let pops = '';
if (relevantNonClientPops.length > 0 && !isListingPops) {
  for (const pop of relevantNonClientPops) {
    pops += '=== ' + pop.titulo + ' ===\n';
    pops += pop.conteudo.substring(0, 5000) + '\n\n';
  }
} else {
  const titulos = allNonClientTitles.map(p => `- ${p.titulo} (${p.categoria || 'Geral'})`).join('\n');
  if (titulos) pops = 'POPs disponíveis (peça pelo nome para ver o conteúdo completo):\n' + titulos;
}

// 8. PARSER DE CLIENTES (Manteve lógica original)
const fonteClientes = clientesContent;
const clientesDB = [];
const linhas = fonteClientes.split('\n');
for (const linha of linhas) {
  let nome = '', cod = '';
  if (linha.includes('\t')) {
    const partes = linha.split('\t').map(p => p.trim());
    const ultimaParte = partes[partes.length - 1];
    if (/^\d+$/.test(ultimaParte)) { cod = ultimaParte; nome = partes[0]; }
  }
  if (!cod) {
    const m = linha.match(/^(.+?)\s{1,}(\d{1,6})\s*$/);
    if (m) { nome = m[1].trim(); cod = m[2].trim(); }
  }
  if (nome && cod && !/^(nome|cód|cod|cliente|código)$/i.test(nome)) {
    clientesDB.push({ nome, cod, nomeLower: nome.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '') });
  }
}

const palavrasMsg = msgLower.split(/\s+/).filter(p => p.length > 2);
const clientesEncontrados = [];
const idsAdicionados = new Set();
for (const cliente of clientesDB) {
  for (const palavra of palavrasMsg) {
    if (cliente.nomeLower.includes(palavra) && !idsAdicionados.has(cliente.cod)) {
      clientesEncontrados.push(cliente.cod + ' - ' + cliente.nome);
      idsAdicionados.add(cliente.cod);
      break;
    }
  }
}

const clienteInfo = clientesEncontrados.length > 0
  ? 'CLIENTES ENCONTRADOS NA BUSCA: ' + clientesEncontrados.join(' | ')
  : 'NENHUM CLIENTE ENCONTRADO COM ESSE NOME';

const colaboradoresStr = colaboradoresArray.length > 0
  ? 'COLABORADORES DA EQUIPE:\n' + colaboradoresArray.map(c => `- ${c.nome}${c.cargo ? ' (' + c.cargo + ')' : ''}${c.funcoes ? ': ' + c.funcoes : ''}`).join('\n')
  : '';

// 9. MONTAGEM FINAL DO SYSTEM CONTENT
let systemContent;
if (systemPromptTemplate && systemPromptTemplate !== '__RESET_TO_DEFAULT__') {
  systemContent = systemPromptTemplate
    .replace(/\{\{DATA\}\}/g, `${dia}/${mes}/${ano}`)
    .replace(/\{\{ANO\}\}/g, String(ano))
    .replace(/\{\{TODAY\}\}/g, today)
    .replace(/\{\{COLABORADORES\}\}/g, colaboradoresStr)
    .replace(/\{\{CLIENTES\}\}/g, clienteInfo)
    .replace(/\{\{POPS\}\}/g, pops)
    .replace(/\{\{HISTORICO\}\}/g, historicoSection);
  systemContent = rulesPrompt + '\n' + systemContent;
} else {
  systemContent = rulesPrompt + '\nVocê é o assistente interno da Zazz Internet, provedor de fibra óptica em Lunardelli-PR. Seu nome é Maluco da IA 👽🍀. Use o emoji 🍀 ocasionalmente.\n\nDATA ATUAL: ' + dia + '/' + mes + '/' + ano + ' (' + today + '). O ANO ATUAL É ' + ano + '.\n\nFORMATAÇÃO OBRIGATÓRIA (WhatsApp):\n- Negrito: use *texto*\n- PROIBIDO usar ** ## ### ou blocos de código\n\n' + colaboradoresStr + '\n\n' + clienteInfo + '\n\nPOPs DA EMPRESA:\n' + pops + historicoSection;
}

// 10. TRAVA DE EXECUÇÃO ÚNICA (Para evitar múltiplas chamadas à API Claude)
if ($input.index > 0) return [];

return [{
  json: {
    chatId: chatId,
    claudeBody: {
      model: "claude-haiku-4-5-20251001",
      max_tokens: 2048,
      system: systemContent,
      messages: [{"role": "user", "content": textMessage}]
    }
  }
}];

