const body = $input.first().json;
const b = body.body || {};
const eData = b.data || b || {};
const eMsg = eData.message || {};
const isAudio = !!(eMsg.audioMessage || eMsg.pttMessage);
if (!isAudio) return [];

const eMsgId = eData.key?.id || '';
const eChat = eData.key?.remoteJid || '';
const fromMe = eData.key?.fromMe || false;
const eSender = eData.pushName || 'Alguém';
const msgTimestamp = eData.messageTimestamp || 0;
const nowTimestamp = Math.floor(Date.now() / 1000);
if (msgTimestamp && (nowTimestamp - msgTimestamp) > 120) return [];

return [{ json: { msgKey: { id: eMsgId, remoteJid: eChat, fromMe }, chatId: eChat, sender: eSender, messageId: eMsgId }}];

const base64 = $json.base64;
if (!base64) return [];
const mimetypeFull = $json.mimetype || 'audio/ogg';
const mimetype = mimetypeFull.split(';')[0].trim();
const ext = mimetype.includes('mp4') ? 'mp4' : mimetype.includes('mpeg') ? 'mp3' : 'ogg';
const detecta = $('Detecta Áudio').first().json;
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(base64, 'base64'),
  'audio.' + ext,
  mimetype
);
return [{
  json: { chatId: detecta.chatId, sender: detecta.sender, messageId: detecta.messageId },
  binary: { audioFile: binaryData }
}];

const transcription = $json.text || '';
const detecta = $('Detecta Áudio').first().json;
if (!transcription) return [];

const botNumbers = ['554396543242', '235437994062039'];
const txtLower = transcription.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const isMentionedText = botNumbers.some(n => transcription.includes('@' + n) || transcription.includes('@' + n.slice(2)));
const isMentionedName = txtLower.includes('maluco') || txtLower.includes('claude');
const isDirectMessage = detecta.chatId && !detecta.chatId.includes('@g.us');
const isMentioned = isMentionedText || isMentionedName || isDirectMessage;

const isReportMensal = txtLower.includes('mensal') || txtLower.includes('mes');
const isReportSemanal = !isReportMensal && (txtLower.includes('semanal') || txtLower.includes('semana'));
const isReport = txtLower.includes('relatorio') || txtLower.includes('resumo');
const reportType = isReportMensal ? 'mensal' : isReportSemanal ? 'semanal' : 'diario';
const isTraining = txtLower.includes('claude aprenda') || txtLower.includes('claude correcao');

return [{
  json: {
    chatId: detecta.chatId,
    textMessage: transcription,
    dbRemetente: detecta.sender + ' 🎤',
    dbMensagem: '🎤 ' + transcription,
    messageId: detecta.messageId,
    isReport, isTraining, reportType, isMentioned
  }
}];
